def demo():
    ble = bluetooth.BLE()
    device = BLEDeviceControl(ble, name="Consumer-IoT")

    adc = machine.ADC(machine.Pin(34))
    try:
        adc.atten(machine.ADC.ATTN_11DB)
    except:
        pass

    def command_handler(cmd, conn_handle):
        parts = cmd.split(":", 1)
        action = parts[0].lower()

        if action == "reboot":
            device.set_status("rebooting")
            time.sleep_ms(500)
            machine.reset()
        elif action == "name" and len(parts) > 1:
            device.set_status("name_locked")
        elif action == "read":
            raw = adc.read()
            voltage = (raw / 4095.0) * 3.3
            device.set_sensor_value(voltage)
            device.set_status("read_ok")
        else:
            device._default_command_handler(cmd)

    device.irq_callback(command_handler)

    while True:
        raw = adc.read()
        voltage = (raw / 4095.0) * 3.3
        device.set_sensor_value(voltage, notify=device.is_connected())
        if not device.is_connected():
            device.set_status("advertising", notify=False)
        time.sleep(2)

if __name__ == "__main__":
    demo()